class Solution(object):
    def minimumOperations(self, grid):
        rows = len(grid)
        cols = len(grid[0])
        total = 0
        for c in range(cols):
            prev = grid[0][c]
            for r in range(1, rows):
                if grid[r][c] <= prev:
                    needed = prev + 1
                    total += needed - grid[r][c]
                    prev = needed
                else:
                    prev = grid[r][c]
        return total
